// Parse Groq AI response safely
const groqResponse = $input.first().json;
let aiData = {};

try {
  const rawContent = groqResponse.choices?.[0]?.message?.content || '{}';
  const cleaned = rawContent.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  aiData = JSON.parse(cleaned);
} catch (e) {
  aiData = {
    facebook_url: null,
    instagram_url: null,
    twitter_url: null,
    tripadvisor_listed: false,
    booking_com_listed: false,
    google_business_likely: false,
    whatsapp_number: null,
    online_score: 0,
    missing_channels: [],
    weakness: 'Could not analyze — manual review needed',
    opportunity: 'Manual review needed'
  };
}

return [{ json: aiData }];

// Merge all data and compute final Online Presence Score
const items = $input.all();
const batchItem = $('Process in Batches').first().json;

// Get website check result
let websiteLive = false;
let statusCode = 0;
try {
  const wsItem = items.find(i => i.json.website_checked);
  websiteLive = wsItem?.json?.website_live || false;
  statusCode = wsItem?.json?.website_status_code || 0;
} catch(e) {}

// Get AI audit result
let aiData = {};
try {
  const aiItem = items.find(i => i.json.hasOwnProperty('online_score'));
  aiData = aiItem?.json || {};
} catch(e) {}

// Compute weighted score (0-100)
let score = 0;
if (batchItem.has_website && websiteLive) score += 25;
if (aiData.facebook_url)            score += 10;
if (aiData.instagram_url)           score += 10;
if (aiData.tripadvisor_listed)      score += 15;
if (aiData.booking_com_listed)      score += 20;
if (aiData.google_business_likely)  score += 20;

score = Math.min(100, score);

// Assign tier
let tier, tier_emoji;
if (score >= 70)      { tier = 'Strong';   tier_emoji = '🟢'; }
else if (score >= 40) { tier = 'Moderate'; tier_emoji = '🟡'; }
else                  { tier = 'Weak';     tier_emoji = '🔴'; }

return [{
  json: {
    business_name:        batchItem.name || 'Unknown',
    category:             batchItem.category || '',
    location:             batchItem.location || '',
    website:              batchItem.website || 'None',
    description:          batchItem.description || '',
    has_website:          batchItem.has_website,
    website_live:         websiteLive,
    website_status_code:  statusCode,
    facebook_url:         aiData.facebook_url || 'Not found',
    instagram_url:        aiData.instagram_url || 'Not found',
    twitter_url:          aiData.twitter_url || 'Not found',
    whatsapp_number:      aiData.whatsapp_number || 'Not found',
    tripadvisor_listed:   aiData.tripadvisor_listed || false,
    booking_com_listed:   aiData.booking_com_listed || false,
    google_business:      aiData.google_business_likely || false,
    online_score:         score,
    tier:                 tier,
    tier_emoji:           tier_emoji,
    full_tier:            tier_emoji + ' ' + tier,
    missing_channels:     (aiData.missing_channels || []).join(', ') || 'None identified',
    weakness:             aiData.weakness || 'Unknown',
    opportunity:          aiData.opportunity || 'Unknown',
    audited_at:           new Date().toISOString(),
    audited_date:         new Date().toLocaleDateString('en-GB')
  }
}];

